import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import './navstyle.css';

function Navbarr() { 
  return (
    <Navbar expand="lg" variant="dark" fixed='top' style={{ backgroundColor: 'rgba(0, 0, 0, 0.7)' }}>
      <Container>
        <Navbar.Brand href="#home">
          
          <img className='logo'
            src="data:image/webp;base64," 
            alt="logo" 
            style={{ width: '30px' }} 
          />
        </Navbar.Brand>
        <Navbar.Toggle aria-controls="basic-navbar-nav" />
        <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
            <Nav.Link href="#Home" className='home' >Home</Nav.Link>
            <Nav.Link href="#skills" className='skills'>Skills</Nav.Link>
            <Nav.Link href="#project" className='projects'>Projects</Nav.Link>
          </Nav>
          <span className="navbar-text">
            <a href='https://www.linkedin.com/in/omar-mohamed-a2a9b7336/' target='_blank'> <img id='img11' src="data:image/png;base64," alt="linkedin" width="10" /></a>
            <a href='https://www.facebook.com/share/1Ai815TGBQ/' target='_blank'> <img id='img2' src="https://upload.wikimedia.org/wikipedia/commons/thumb/0/05/Facebook_Logo_%282019%29.png/500px-Facebook_Logo_%282019%29.png" alt="facebook" width="20" /></a>
            <a href='https://www.instagram.com/omarjad__?igsh=MWg1NHNsemsxZGJqMA==' target='_blank'> <img id='img3' src="data:image/jpeg;base64," alt="insta" width="20" /></a>
          </span>

         
          <button className='clicktoconnect' onClick={() => console.log('pressed')}>
            <span> Let's connect</span>
          </button>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  );
}

export default Navbarr;