import Container from "react-bootstrap/Container";
import Col from 'react-bootstrap/Col';
import Row from 'react-bootstrap/Row'; 
import './banstyle.css';

function Banner() { 
  return (
    <section className="Banner" id='Home'>
      <Container>
        <Row className="flexx">
          
          <Col className="align-items-left" xs={12} md={6} xl={7}>
            <div className="welcome"> Welcome to my portfolio</div>
            <br />
            <h1 className="wrap">Hello i am Omar a cybersecurity specialist  </h1>
            <p>
              Here is my portfolio so you can know me better and if you want to talk don't hesitate to click on the button 
            </p>
            <button className='clicktoconnectt' onClick={() => console.log('pressed')}>
              <span> Let's connect {`=>`}</span>
            </button>
          </Col>

          <Col xs={12} md={6} xl={5} className="d-flex justify-content-end">
          <a href="https://github.com/Omar-Jad" target="_blank">
           <img id ='img1' src='data:image/jpeg;base64,' alt='small photo' style={{cursor: 'pointer'}}></img>
          </a>
          </Col>
        </Row>
      </Container>
    </section>
  );
}

export default Banner;